#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
push-setup.py — отправляет агенту «Ozon Analyst» серию сообщений в чат через REST API,
чтобы он сам сохранил все файлы шаблона. Запуск из твоего терминала:

    ASCN_BASE=https://api.clawman.ascn.ai/api/v1/workspaces/ws-XXXX ASCN_KEY=<key> python3 push-setup.py

Ключ можно передать через ASCN_KEY, адрес воркспейса — через ASCN_BASE (иначе плейсхолдеры ниже).
После прогона добавь секреты (OZON_CLIENT_ID/OZON_API_KEY) и проверь, что первое обращение
запускает онбординг. Ключ стоит сменить после использования (он передавался открытым текстом).
"""
import base64, json, os, sys, time, uuid
import urllib.request, urllib.error

BASE = os.environ.get("ASCN_BASE", "https://api.clawman.ascn.ai/api/v1/workspaces/<YOUR_WORKSPACE_ID>")
API_KEY = os.environ.get("ASCN_KEY", "<YOUR_ASCN_KEY>")

FILES = json.loads(base64.b64decode("").decode("utf-8"))

def send(sid, content):
    url = BASE + "/session/" + sid + "/messages"
    data = json.dumps({"content": content}).encode("utf-8")
    req = urllib.request.Request(url, data=data, method="POST", headers={
        "Content-Type": "application/json",
        "Authorization": "Bearer " + API_KEY,
    })
    try:
        with urllib.request.urlopen(req, timeout=120) as r:
            return r.status, r.read().decode("utf-8", "replace")
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode("utf-8", "replace")
    except Exception as e:
        return None, repr(e)

def main():
    sid = str(uuid.uuid4())
    print("session_id:", sid)
    intro = "Ты настраиваешься как шаблон «Ozon Analyst». Сейчас пришлю серию файлов. Для каждого: создай или перезапиши файл по указанному пути СТРОГО с присланным содержимым, дословно, без правок. Пока НЕ запускай онбординг — только сохраняй файлы и коротко подтверждай каждый."
    st, body = send(sid, intro)
    print("intro ->", st)
    if st is None:
        print("Сеть/эндпоинт недоступны:", body); sys.exit(1)
    time.sleep(2)
    n = len(FILES)
    for i, f in enumerate(FILES, 1):
        msg = (
            "Файл {}/{}: {}\n".format(i, n, f["label"]) +
            "Что это: {}\n".format(f["desc"]) +
            "Куда сохранить (путь в воркспейсе): {}\n".format(f["path"]) +
            "Действие: создай/перезапиши файл по этому пути и вставь содержимое между "
            "маркерами ДОСЛОВНО, один в один, без правок и без самих строк-маркеров.\n" +
            "----- BEGIN {} -----\n".format(f["path"]) +
            f["content"] + "\n" +
            "----- END {} -----".format(f["path"])
        )
        st, body = send(sid, msg)
        print(f["path"], "->", st)
        time.sleep(2)
    final = "Все файлы отправлены. Перечитай базу знаний и скиллы. С этого момента при первом обращении пользователя, если setup=PENDING или в files/data/cost_prices.json стоит плейсхолдер «ВАШ-OFFER-ID», запускай скилл onboarding. Подтверди готовность."
    st, body = send(sid, final)
    print("final ->", st)
    print("\nГотово. session_id =", sid)

if __name__ == "__main__":
    main()
